### Tested versions

- Reproducible in: 4.5 Stable.
- Not reproducible in: 4.4.1 Stable.

### System information

Godot v4.5.stable - Windows 10 (build 19045) - Multi-window, 1 monitor - Vulkan (Forward+) - integrated AMD Radeon(TM) R3 Graphics (Advanced Micro Devices, Inc.; 27.20.20913.2000) - AMD A4-9120 RADEON R3, 4 COMPUTE CORES 2C+2G (2 threads) - 11.43 GiB memory

### Issue description

<div align="justify">
I'm probably doing something wrong. I'm working on nodes for visual shader system based on the main branch

https://github.com/godotengine/godot/blob/master/servers/rendering/renderer_rd/shaders/scene_forward_lights_inc.glsl 

and I recently updated to version 4.5 where specular lighting behaves differently on metallic materials, for diffuse lighting I use the burley implementation and for specular lighting SchlickGGX (NDF (Trowbridge-Reitz), G (Implicit), F (Schlick's Approximation)).
</div>

<br>

<div align="center">
<br>
<img width="1024" height="1024" alt="Image" src="https://github.com/user-attachments/assets/f6b82ab3-26bd-4a5d-82a1-bca368ea30ac" />
<br>
Render in Orthogonal Camera Error Specular light | Godot v4.4.1 vs Godot v4.5 | Standard Material vs. Custom Material
<br>
Albedo = Hex #00ffff || vec3(0.0, 1.0, 1.0)
<br>
Roughness = 1.0
<br>
Metallic = 1.0
<br>
Metallic Specular = 1.0
</div>

### Steps to reproduce

Create a new project
Create a MeshInstance3D scene
Add a SphereMesh
Create a Shaderd Material .tres and add a new shader .gdshader
Copy the following Spatial code

Set Albedo = vec3(0.0, 1.0, 1.0)
Set Roughness = 1.0
Set Metallic = 1.0
Set Metallic Specular = 1.0

Compare with StandardMaterial

```
shader_type spatial;

const float INV_PI = 0.318309;

uniform vec3 diffuse_color : source_color = vec3(1.0);
uniform float roughness : hint_range(0.0, 1.0, 0.01) = 1.0;
uniform float metallic : hint_range(0.0, 1.0, 0.01) = 0.0;
uniform float metallic_specular : hint_range(0.0, 1.0, 0.01) = 0.5;

float diffuse_burley(
	in float cNdotL,
	in float cNdotV,
	in float cHdotL,
	in float sigma // Roughness.
)
{
	// https://media.disneyanimation.com/uploads/production/publication_asset/48/asset/s2012_pbs_disney_brdf_notes_v3.pdf 
	float FD90 = 2.0 * sigma * cHdotL * cHdotL - 0.5;

	float fd_L = 1.0 + (FD90) * pow(1.0 - cNdotL, 5.0);
	float fd_V = 1.0 + (FD90) * pow(1.0 - cNdotV, 5.0);

	return  fd_V * fd_L * cNdotL * INV_PI;
}

vec3 specular_schlick_ggx(
	in float cNdotL,
	in float cNdotV,
	in float cHdotN,
	in float cHdotL,
	in vec3 rho, // Diffuse Color.
	in float sigma, // Roughness.
	in float m, // Metallic.
	in float s // Metallic Specular.
)
{
	// https://github.com/godotengine/godot/blob/master/servers/rendering/renderer_rd/shaders/scene_forward_lights_inc.glsl
	float a = sigma * sigma; // Variance.
	float a2 = a * a;

	/* Normal Distribution Function (Trowbridge-Reitz) */
	float D = 1.0 + (a2 - 1.0) * cHdotN * cHdotN;

	D = a2 / (PI * D * D);

	/* Geometric Function (Implicit) */
	float G = 0.5 / mix(2.0 * cNdotL * cNdotV, cNdotL + cNdotV, a);

	/* Fresnel Function (Schlick’s Approximation) */
	float dielectric = 0.16 * s * s;

	vec3 f0 = mix(vec3( dielectric ), rho, vec3( m )); 
	float f90 = clamp(dot(f0, vec3(16.5)), m, 1.0);

	vec3 F = f0 + (f90 - f0) * pow(1.0 - cHdotL, 5.0);

	return max(D * G * F * cNdotL, 0.0);
}

void fragment()
{
	ALBEDO = diffuse_color;
	ROUGHNESS = roughness;
	METALLIC = metallic;
	SPECULAR = metallic_specular;
}

void light()
{
	vec3 n = normalize( NORMAL );
	vec3 l = normalize( LIGHT );
	vec3 v = normalize( VIEW );

	vec3 h = normalize(v + l); // Halfway Vector.

	float NdotL = dot(n, l); // [-1.0, 1.0].
	float NdotV = dot(n, v); // [-1.0, 1.0].

	float HdotN = dot(h, n); // [-1.0, 1.0].
	float HdotL = dot(h, l); // [-1.0, 1.0].

	float cNdotL = max(NdotL, 0.0); // [0.0, 1.0].
	float cNdotV = max(NdotV, 0.0); // [0.0, 1.0].

	float cHdotN = max(HdotN, 0.0); // [0.0, 1.0].
	float cHdotL = max(HdotL, 0.0); // [0.0, 1.0].

	/* Diffuse Burley */ 
	float d = diffuse_burley(cNdotL, cNdotV, cHdotL, ROUGHNESS);

	/* Specular Schlick-GGX */
	vec3 s = specular_schlick_ggx(cNdotL, cNdotV, cHdotN, cHdotL, ALBEDO, ROUGHNESS, METALLIC, metallic_specular);

	DIFFUSE_LIGHT += LIGHT_COLOR * ATTENUATION * d;
	SPECULAR_LIGHT += LIGHT_COLOR * ATTENUATION * s;
}
```

or install the following addon:
Asset Lib -> Import -> .zip -> check Ignore root -> Install
Place the specular_schlick_ggx.tres material on a MeshInstance3D node


